/** Minimal external declaration for the JavaScript [Intl](https://developer.mozilla.org/en-US/docs/Web/JavaScript/Reference/Global_Objects/Intl) API. */
public external class Intl {

	/** A JS Intl.Locale wrapping a BCP 47 language tag string. */
	public class Locale(tag: String)
}
